def is_prime(num):
    if num <= 1:
        return False
    for index in range(2, int(num**0.5) + 1):
        if num % index == 0:
            return False
    return True

def words_in_sentence(text):
    word_list = text.split(' ')
    prime_length_words = [word for word in word_list if is_prime(len(word))]
    return ' '.join(prime_length_words)
